arguments.new_str:
var builder = WebApplication.CreateBuilder(args);

// FIX 1 – ValidateScopes (now on by default in Development):
//   A Singleton capturing a Scoped service throws InvalidOperationException.
//   Corrected: register CacheService as Scoped so lifetimes are compatible.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX 2 – HttpClientFactory primary handler is now SocketsHttpHandler:
//   The cast to HttpClientHandler throws InvalidCastException in .NET 9.
//   Use ConfigurePrimaryHttpMessageHandler to set properties directly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false });

// FIX 3 – Forwarded Headers Middleware now ignores unknown proxies:
//   X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks
//   are silently dropped. Add your reverse proxy address.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});

// FIX 4 – HttpClientFactory Trace-level header logging is now redacted:
//   All header values are redacted by default. Allowlist non-sensitive
//   headers you need to see when debugging behind the reverse proxy.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Forwarded-For"
        && h != "X-Forwarded-Proto"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

// FIX 5 – dotnet watch + Hot Reload:
//   The .NET 9 SDK's dotnet watch is incompatible with Hot Reload when
//   targeting older frameworks. Now that TFM is net9.0, no code change is
//   needed, but if you multi-target net8.0, use the matching SDK version
//   for watch: e.g.  dotnet8-sdk dotnet watch

